// https://github.com/gleam-lang/gleam/issues/4883
#[test]
fn variant_inference_ignores_echo() {
    assert_module_infer!(
        "
pub type Wibble {
  Wibble(wibble: Int, wobble: String)
  Wobble(a: String, b: Int)
}

pub fn get_int(w: Wibble) {
  case echo w {
    Wibble(..) -> w.wibble
    Wobble(..) -> w.b
  }
}
",
        vec![
            ("Wibble", "fn(Int, String) -> Wibble"),
            ("Wobble", "fn(String, Int) -> Wibble"),
            ("get_int", "fn(Wibble) -> Int"),
        ]
    );
}

#[test]
fn correct_type_check_for_multiple_mutually_recursive_functions() {
    assert_module_error!(
        r#"
pub fn wibble(id) {
  wobble(id, True)
}

pub fn wobble(id, bool) {
  case bool {
    True -> wibble(id)
    False -> wubble(id, bool)
  }
}

pub fn wubble(id, bool) {
  case bool {
    True -> final(id)
    False -> wobble(id, bool)
  }
}

pub fn final(id) {
  let #(a, b) = id
  echo #(a, b)
}

pub fn main() {
  wibble(#("a", "b"))
  wibble(2)
}
"#
    );
}

#[test]
fn prepend_constant_list() {
    assert_module_infer!(
        "
const list = [3, 4, 5]
pub const full_list = [1, 2, ..list]
",
        vec![("full_list", "List(Int)")],
    );
}

#[test]
fn prepend_constant_list_from_other_module() {
    assert_module_infer!(
        ("mod", "pub const list = [3, 4, 5]"),
        "
import mod

pub const full_list = [1, 2, ..mod.list]
",
        vec![("full_list", "List(Int)")],
    );
}

#[test]
fn prepend_constant_list_wrong_type() {
    assert_module_error!(
        "
const pi = 3.14
pub const full_list = [1.0, 2.0, ..pi]
"
    );
}

#[test]
fn prepend_constant_list_wrong_element_type() {
    assert_module_error!(
        "
const list = [3, 4, 5]
pub const full_list = [1.0, 2.0, ..list]
"
    );
}

